ALTER TABLE "Brand" ADD COLUMN IF NOT EXISTS "status" TEXT NOT NULL DEFAULT 'approved', ADD COLUMN IF NOT EXISTS "approvedAt" TIMESTAMP(3), ADD COLUMN IF NOT EXISTS "approvedBy" TEXT, ADD COLUMN IF NOT EXISTS "rejectionReason" TEXT, ADD COLUMN IF NOT EXISTS "archivedAt" TIMESTAMP(3);
CREATE TABLE IF NOT EXISTS "UserChallenge" ("id" TEXT NOT NULL, "userId" TEXT NOT NULL, "challengeId" TEXT NOT NULL, "status" TEXT NOT NULL DEFAULT 'active', "progressCurrent" INTEGER NOT NULL DEFAULT 0, "progressTotal" INTEGER NOT NULL DEFAULT 1, "activatedAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "completedAt" TIMESTAMP(3), "completionSource" TEXT, "rewardIssuedAt" TIMESTAMP(3), "qrToken" TEXT, CONSTRAINT "UserChallenge_pkey" PRIMARY KEY ("id"));
CREATE UNIQUE INDEX IF NOT EXISTS "UserChallenge_userId_challengeId_key" ON "UserChallenge"("userId","challengeId"); CREATE UNIQUE INDEX IF NOT EXISTS "UserChallenge_qrToken_key" ON "UserChallenge"("qrToken"); CREATE INDEX IF NOT EXISTS "UserChallenge_userId_status_idx" ON "UserChallenge"("userId","status");
CREATE TABLE IF NOT EXISTS "UserChallengeEvent" ("id" TEXT NOT NULL, "userId" TEXT NOT NULL, "challengeId" TEXT NOT NULL, "participationId" TEXT NOT NULL, "type" TEXT NOT NULL, "metadata" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "UserChallengeEvent_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "UserReward" ("id" TEXT NOT NULL, "userId" TEXT NOT NULL, "participationId" TEXT NOT NULL, "title" TEXT NOT NULL, "description" TEXT, "status" TEXT NOT NULL DEFAULT 'available', "qrToken" TEXT NOT NULL, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "usedAt" TIMESTAMP(3), "expiresAt" TIMESTAMP(3), CONSTRAINT "UserReward_pkey" PRIMARY KEY ("id")); CREATE UNIQUE INDEX IF NOT EXISTS "UserReward_participationId_key" ON "UserReward"("participationId"); CREATE UNIQUE INDEX IF NOT EXISTS "UserReward_qrToken_key" ON "UserReward"("qrToken");
CREATE TABLE IF NOT EXISTS "WalletTransaction" ("id" TEXT NOT NULL, "userId" TEXT NOT NULL, "amount" INTEGER NOT NULL, "type" TEXT NOT NULL, "metadata" JSONB, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, CONSTRAINT "WalletTransaction_pkey" PRIMARY KEY ("id"));
CREATE TABLE IF NOT EXISTS "AdminAction" ("id" TEXT NOT NULL, "adminEmail" TEXT NOT NULL, "actionType" TEXT NOT NULL, "entityType" TEXT NOT NULL, "entityId" TEXT, "before" JSONB, "after" JSONB, "metadata" JSONB, "comment" TEXT, "createdAt" TIMESTAMP(3) NOT NULL DEFAULT CURRENT_TIMESTAMP, "brandId" TEXT, CONSTRAINT "AdminAction_pkey" PRIMARY KEY ("id")); CREATE INDEX IF NOT EXISTS "AdminAction_createdAt_idx" ON "AdminAction"("createdAt");
ALTER TABLE "UserChallenge" ADD CONSTRAINT "UserChallenge_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "UserChallenge" ADD CONSTRAINT "UserChallenge_challengeId_fkey" FOREIGN KEY ("challengeId") REFERENCES "BrandChallenge"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "UserChallengeEvent" ADD CONSTRAINT "UserChallengeEvent_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "UserChallengeEvent" ADD CONSTRAINT "UserChallengeEvent_challengeId_fkey" FOREIGN KEY ("challengeId") REFERENCES "BrandChallenge"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "UserChallengeEvent" ADD CONSTRAINT "UserChallengeEvent_participationId_fkey" FOREIGN KEY ("participationId") REFERENCES "UserChallenge"("id") ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE "UserReward" ADD CONSTRAINT "UserReward_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "UserReward" ADD CONSTRAINT "UserReward_participationId_fkey" FOREIGN KEY ("participationId") REFERENCES "UserChallenge"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "WalletTransaction" ADD CONSTRAINT "WalletTransaction_userId_fkey" FOREIGN KEY ("userId") REFERENCES "User"("id") ON DELETE CASCADE ON UPDATE CASCADE; ALTER TABLE "AdminAction" ADD CONSTRAINT "AdminAction_brandId_fkey" FOREIGN KEY ("brandId") REFERENCES "Brand"("id") ON DELETE SET NULL ON UPDATE CASCADE;
